import grpc
from concurrent import futures
import time
import logging

from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2
from google.rpc import code_pb2

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, auth_token=None, required_header=None):
        self.auth_token = auth_token or "valid-token-12345"
        self.required_header = required_header or "x-auth-token"
        
    def Check(self, request, context):
        logger.info("Received authorization check request")
        
        headers = request.attributes.request.http.headers
        method = request.attributes.request.http.method
        path = request.attributes.request.http.path
        
        logger.info(f"Request: {method} {path}")
        logger.info(f"Headers: {dict(headers)}")
        
        auth_header = headers.get(self.required_header, "")
        
        if self._is_authorized(auth_header, headers):
            logger.info("Authorization successful")
            return self._create_ok_response(headers)
        else:
            logger.warning("Authorization failed")
            return self._create_denied_response()
    
    def _is_authorized(self, auth_header, all_headers):
        if auth_header == self.auth_token:
            return True
        
        authorization = all_headers.get("authorization", "")
        if authorization.startswith("Bearer "):
            token = authorization[7:]
            if token == self.auth_token:
                return True
        
        return False
    
    def _create_ok_response(self, request_headers):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-auth-status",
                    value="authorized"
                )
            )
        )
        
        user_id = request_headers.get("x-user-id", "unknown")
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-validated-user",
                    value=user_id
                )
            )
        )
        
        return response
    
    def _create_denied_response(self):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.PERMISSION_DENIED
        response.status.message = "Unauthorized: Invalid or missing authentication token"
        
        response.denied_response.status.code = http_status_pb2.StatusCode.Unauthorized
        
        response.denied_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="content-type",
                    value="application/json"
                )
            )
        )
        
        response.denied_response.body = '{"error": "Unauthorized", "message": "Invalid or missing authentication token"}'
        
        return response


def serve(port=50051, auth_token=None, required_header=None):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    auth_service = AuthorizationService(auth_token=auth_token, required_header=required_header)
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(auth_service, server)
    
    server.add_insecure_port(f'[::]:{port}')
    
    logger.info(f"Starting Envoy External Authorization server on port {port}")
    server.start()
    
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        logger.info("Shutting down server")
        server.stop(0)


if __name__ == '__main__':
    serve(port=50051, auth_token="valid-token-12345", required_header="x-auth-token")